```class Solution {
public:
    int numberOfSpecialChars(string word) {
        int count = 0;
        for (int i = 0; i < word.length(); i++) {
            if (word[i] == word[i+1] && word[i] != ' ') {
                count++;
            }
        }
        return count;
    }
};
```

